const product = $('PostgreSQL: Fetch Product').item.json;
const guidelinesRows = $('PostgreSQL: Fetch Brand Guidelines').all().map(i => i.json);
const body = $('Webhook: Generate Content').item.json.body;

const guidelines = {};
guidelinesRows.forEach(row => { guidelines[row.key] = row.value; });

const guidelinesText = Object.entries(guidelines)
  .map(([k, v]) => `${k.toUpperCase()}: ${v}`)
  .join('\n');

const systemPrompt = `You are an expert social media content creator for an automotive car mods and imports brand targeting the JDM and import car enthusiast scene.

BRAND GUIDELINES:
${guidelinesText}

PRODUCT DETAILS:
Name: ${product.name}
Category: ${product.category || 'N/A'}
Brand: ${product.brand || 'N/A'}
Description: ${product.description || 'N/A'}

You have access to a web search tool. Use it to search for current trending content related to this product before generating content.

TIKTOK SCRIPT REQUIREMENTS — READ CAREFULLY:
- The script must be a FULL 60-second video script, approximately 150-160 spoken words total.
- [HOOK] (0–3s): 1–2 punchy sentences that stop the scroll. ~15–20 words.
- [BODY] (3–50s): The main delivery — features, story, demo, social proof. Must be ~115–125 words across multiple natural spoken lines. Do NOT summarize or write placeholder phrases like "(explain features)". Write every single spoken word out in full.
- [CTA] (50–60s): A clear, direct call-to-action. ~15–20 words.
- Write this as a real person speaking on camera — conversational, energetic, authentic to JDM culture.
- Do NOT truncate or abbreviate any section.

After researching trends, respond ONLY with valid JSON (no markdown, no code blocks):
{
  "tiktok_script": "Complete 60-second spoken script (~150 words total). Label each section: [HOOK], [BODY], [CTA]. Write every spoken word — no placeholders, no summarizing.",
  "instagram_caption": "Caption with emojis, line breaks, and relevant hashtags at the end",
  "visual_direction": "Camera angles, lighting mood, props, outfit/styling, location, and editing style suggestions"
}`;

const userPrompt = `Create social media content for: ${product.name}

Marketing Objective: ${body.marketing_objective}

First search for: "${product.name} ${product.category} automotive TikTok trend 2025" to find current trends, then generate the content.`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    product_id: product.id,
    marketing_objective: body.marketing_objective,
    session_id: String(product.id)
  }
}];

const agentOutput = $input.item.json.output;
const prev = $('Code: Build Agent Prompt').item.json;

let cleaned = (agentOutput || '').trim();

// Strip markdown code fences if present
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```json?\n?/, '').replace(/\n?```$/, '').trim();
}

let parsed;
try {
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch (e) {
  parsed = {
    tiktok_script: agentOutput || 'Parse error',
    instagram_caption: 'Parse error — see raw output',
    visual_direction: 'Parse error — see raw output'
  };
}

return [{
  json: {
    tiktok_script: parsed.tiktok_script || '',
    instagram_caption: parsed.instagram_caption || '',
    visual_direction: parsed.visual_direction || '',
    product_id: prev.product_id,
    marketing_objective: prev.marketing_objective
  }
}];
